import html
from pathlib import Path
from typing import Dict, Union

TEMPLATE_DIR = Path(__file__).parent.parent / 'templates'


class SafeString(str):
    """A string that should not be HTML-escaped."""
    pass


def mark_safe(value: str) -> SafeString:
    """Mark a string as safe HTML (won't be escaped)."""
    return SafeString(value)


class TemplateEngine:
    def render(self, template_name: str, context: Dict[str, Union[str, SafeString]]) -> str:
        template_path = TEMPLATE_DIR / template_name
        if not template_path.exists():
            raise FileNotFoundError(f'Template {template_name} not found')

        content = template_path.read_text()

        for key, value in context.items():
            placeholder = '{{' + key + '}}'
            if isinstance(value, SafeString):
                safe_value = str(value)
            else:
                safe_value = html.escape(str(value))
            content = content.replace(placeholder, safe_value)

        return content
